INSERT INTO stadium_teams (stadium_id, team_id) SELECT s.id, t.id FROM stadiums s CROSS JOIN teams t WHERE s.name = 'Tallaght Stadium' AND t.name = 'Shamrock Rovers' AND NOT EXISTS (SELECT 1 FROM stadium_teams st WHERE st.stadium_id = s.id AND st.team_id = t.id);
INSERT INTO stadium_teams (stadium_id, team_id) SELECT s.id, t.id FROM stadiums s CROSS JOIN teams t WHERE s.name = 'Dalymount Park' AND t.name = 'Bohemian FC' AND NOT EXISTS (SELECT 1 FROM stadium_teams st WHERE st.stadium_id = s.id AND st.team_id = t.id);
INSERT INTO stadium_teams (stadium_id, team_id) SELECT s.id, t.id FROM stadiums s CROSS JOIN teams t WHERE s.name = 'Stade Jos Nosbaum' AND t.name = 'F91 Dudelange' AND NOT EXISTS (SELECT 1 FROM stadium_teams st WHERE st.stadium_id = s.id AND st.team_id = t.id);
